const body = $json.body || $json;
if (!body.provider || !body.input) throw new Error('provider + input required');
return [{ json: {
  correlationId: `inv-issue-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  startedAt: new Date().toISOString(),
  provider: body.provider,
  input: body.input,
  attempt: 0,
  maxAttempts: 3,
  backoffMs: [2000, 4000, 8000]
}}];

const s = $input.first().json;
const nextAttempt = (s.attempt ?? 0) + 1;
if (nextAttempt > s.maxAttempts) return [{ json: { ...s, attempt: nextAttempt, exhausted: true } }];
return [{ json: { ...s, attempt: nextAttempt, waitMs: s.backoffMs[nextAttempt - 1] } }];
